                        </span>
                        <span className="text-[40px]  font-headline font-black text-white/90 italic truncate block">
                          ₱
                          {approvedReservationRevenue.toLocaleString("en-US", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2,
                          })}
                        </span>
                      </div>
                    </div>
                  </>
                );
              })()}
            </section>
          </div>
        </div>
      </main>
    </div>
  );
}

