"use client";
import { useState, useEffect } from "react";
import { createClient } from "../../../lib/supabase/client";
import { useRouter } from "next/navigation";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import emailjs from "@emailjs/browser";
import * as XLSX from "xlsx";
import dynamic from "next/dynamic";
import Image from "next/image";

const DynamicCriticalStockModal = dynamic(
  () => import("../../components/CriticalStockModal"),
  {
    ssr: false,
  },
);

const DynamicOrderStatusConfirmationModal = dynamic(
  () => import("../../components/OrderStatusConfirmationModal"),
  {
    ssr: false,
  },
);

const DynamicToast = dynamic(() => import("../../components/Toast"), {
  ssr: false,
});

export default function AdminDashboard() {
  const [isStockModalOpen, setIsStockModalOpen] = useState(false);
  const [lowStockProducts, setLowStockProducts] = useState([]);
  const [topProducts, setTopProducts] = useState([]);
  const [recentActivities, setRecentActivities] = useState([]);
  const [newArrivals, setNewArrivals] = useState([]);
  const [data, setData] = useState({
    totalReservations: 0,
    pendingReservations: 0,
    revenueEstimate: 0,
    criticalStockCount: 0,
    loading: true,
  });
  const [activeReservation, setActiveReservation] = useState(null);
  const [isDetailsModalOpen, setIsDetailsModalOpen] = useState(false);
  const [confirmModal, setConfirmModal] = useState({
    isOpen: false,
    reservationId: null,
    newStatus: null,
    customerEmail: null,
    customerName: null,
    productName: null,
  });
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "success",
  });

  // Revenue Graph States
  const [dateRange, setDateRange] = useState("Last 30 Days");
  const [revenueData, setRevenueData] = useState([]);
  const [totalRevenue, setTotalRevenue] = useState(0);

  const supabase = createClient();

  const router = useRouter();

  const showToast = (message, type = "success") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ ...toast, visible: false }), 4000);
  };

  useEffect(() => {
    fetchDashboardData();
    fetchAllAnalytics();
  }, [dateRange]);

  const fetchAllAnalytics = async () => {
    // 1. Calculate Date Bounds
    const now = new Date();
    let startDate = new Date();
    let endDate = new Date();

    switch (dateRange) {
      case "Last 7 Days":
        startDate.setDate(now.getDate() - 7);
        break;
      case "This Month":
        startDate = new Date(now.getFullYear(), now.getMonth(), 1);
        break;
      case "Last Month":
        startDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        endDate = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
        break;
      case "Annual":
        // Use the calendar year for Annual: Jan 1 -> Dec 31 of current year
        startDate = new Date(now.getFullYear(), 0, 1);
        endDate = new Date(now.getFullYear(), 11, 31, 23, 59, 59);
        break;
      default:
        startDate.setDate(now.getDate() - 30);
    }

    // Fetch POS data (actual sales) to compute Total Revenue and chart
    const { data: posData, error: posError } = await supabase
      .from("POS")
      .select("quantity, created_at, Inventory(price, item_name)")
      .gte("created_at", startDate.toISOString())
      .lte("created_at", endDate.toISOString());

    if (posError || !posData) {
      console.error("Error fetching POS analytics:", posError);
      return;
    }

    // Process POS revenue
    let sumRev = 0;

    if (dateRange === "Annual") {
      const monthlyRevenue = {};
      posData.forEach((res) => {
        if (res.Inventory?.price) {
          const rev = res.quantity * res.Inventory.price;
          sumRev += rev;
          const d = new Date(res.created_at);
          const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
          monthlyRevenue[key] = (monthlyRevenue[key] || 0) + rev;
        }
      });

      const chartData = [];
      for (let m = 0; m < 12; m++) {
        const key = `${now.getFullYear()}-${String(m + 1).padStart(2, "0")}`;
        const monthName = new Date(now.getFullYear(), m, 1).toLocaleDateString(
          "en-US",
          { month: "short" },
        );
        chartData.push({ name: monthName, revenue: monthlyRevenue[key] || 0 });
      }
      setTotalRevenue(sumRev);
      setRevenueData(chartData);
    } else {
      const dailyRevenue = {};
      posData.forEach((res) => {
        if (res.Inventory?.price) {
          const rev = res.quantity * res.Inventory.price;
          sumRev += rev;
          const dateStr = res.created_at.split("T")[0];
          dailyRevenue[dateStr] = (dailyRevenue[dateStr] || 0) + rev;
        }
      });

      setTotalRevenue(sumRev);
      const chartData = Object.keys(dailyRevenue)
        .sort((a, b) => new Date(a) - new Date(b))
        .map((dateStr) => ({
          name: new Date(dateStr).toLocaleDateString("en-US", {
            month: "short",
            day: "2-digit",
          }),
          revenue: dailyRevenue[dateStr],
        }));
      setRevenueData(chartData);
    }

    // Top Products (based on actual POS sales)
    const productCounts = {};
    let totalReserved = 0;

    posData.forEach((res) => {
      const name = res.Inventory?.item_name;
      if (name) {
        productCounts[name] = (productCounts[name] || 0) + res.quantity;
        totalReserved += res.quantity;
      }
    });

    const sortedProducts = Object.keys(productCounts)
      .map((name) => ({
        name,
        units: productCounts[name],
        percentage:
          totalReserved > 0
            ? Math.round((productCounts[name] / totalReserved) * 100)
            : 0,
      }))
      .sort((a, b) => b.units - a.units);

    setTopProducts(sortedProducts.slice(0, 5));
  };

  const fetchDashboardData = async () => {
    try {
      // 1. Fetch Reservations
      const { data: resData } = await supabase
        .from("Reservation")
        .select("status");

      const { data: invData } = await supabase
        .from("Inventory")
        .select("item_name, item_image, brand, stock, reorder_point");
      setData({
        totalReservations: resData?.length || 0,
        pendingReservations:
          resData?.filter((r) => r.status === "Pending").length || 0,
        criticalStockCount: invData?.filter((i) => i.stock <= 5).length || 0,
        loading: false,
      });

      const criticalItems = invData?.filter((i) => i.stock <= 5) || [];
      setLowStockProducts(criticalItems);

      // activity ledger recent reservations
      const { data: ActivityData } = await supabase
        .from("Reservation")
        .select("id, created_at, status, Inventory(item_name, item_image)")
        .order("created_at", { ascending: false })
        .limit(5);

      // new added products from inventory
      const { data: arrivalsData } = await supabase
        .from("Inventory")
        .select("id, item_name, price, item_image")
        .order("created_at", { ascending: false })
        .limit(4);

      setRecentActivities(ActivityData || []);
      setNewArrivals(arrivalsData || []);

      // fetch recent reservations with customer data to display in acitivity ledger modal
      const { data: activityData } = await supabase
        .from("Reservation")
        .select("*, Users(email), Inventory(item_name, item_image, brand)")
        .order("created_at", { ascending: false })
        .limit(5);

      const { data: customerData } = await supabase
        .from("Customer")
        .select("user_id, firstname, lastname");
      if (activityData && customerData) {
        const merged = activityData.map((res) => {
          const customer = customerData.find((c) => c.user_id === res.user_id);
          return {
            ...res,
            customer_name: customer
              ? `${customer.firstname} ${customer.lastname}`
              : "Unknown Customer",
            customer_email: res.Users?.email,
          };
        });
        setRecentActivities(merged);
      }
    } catch (error) {
      console.error("Error fetching dashboard data:", error);
    }
  };

  const exportToExcel = async () => {
    try {
      const workbook = XLSX.utils.book_new();

      // determine date bounds based on `dateRange`
      const now = new Date();
      let startDate = new Date();
      let endDate = new Date();

      switch (dateRange) {
        case "Last 7 Days":
          startDate = new Date(now);
          startDate.setDate(now.getDate() - 7);
          break;
        case "This Month":
          startDate = new Date(now.getFullYear(), now.getMonth(), 1);
          endDate = new Date(
            now.getFullYear(),
            now.getMonth() + 1,
            0,
            23,
            59,
            59,
          );
          break;
        case "Last Month":
          startDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
          endDate = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59);
          break;
        case "Annual":
          startDate = new Date(now.getFullYear(), 0, 1);
          endDate = new Date(now.getFullYear(), 11, 31, 23, 59, 59);
          break;
        default:
          startDate.setDate(now.getDate() - 30);
      }

      // --- SHEET 1: REVENUE SUMMARY (POS) ---
      const { data: posData, error: posErr } = await supabase
        .from("POS")
        .select("quantity, created_at, Inventory(price, item_name)")
        .gte("created_at", startDate.toISOString())
        .lte("created_at", endDate.toISOString());

      if (posErr) throw posErr;

      let revenueExport = [];
      let grandTotal = 0;

      if (dateRange === "Annual") {
        // monthly aggregation
        const monthly = Array(12).fill(0);
        posData.forEach((p) => {
          if (p.Inventory?.price) {
            const rev = p.quantity * p.Inventory.price;
            const m = new Date(p.created_at).getMonth();
            monthly[m] += rev;
            grandTotal += rev;
          }
        });

        const monthNames = [
          "January",
          "February",
          "March",
          "April",
          "May",
          "June",
          "July",
          "August",
          "September",
          "October",
          "November",
          "December",
        ];

        revenueExport = monthNames.map((mn, i) => ({
          Month: mn,
          "Total Revenue (PHP)": Number(monthly[i].toFixed(2)),
        }));
      } else {
        // daily aggregation
        const daily = {};
        posData.forEach((p) => {
          if (p.Inventory?.price) {
            const rev = p.quantity * p.Inventory.price;
            const dKey = p.created_at.split("T")[0];
            daily[dKey] = (daily[dKey] || 0) + rev;
            grandTotal += rev;
          }
        });
        revenueExport = Object.keys(daily)
          .sort((a, b) => new Date(a) - new Date(b))
          .map((dateStr) => ({
            Date: new Date(dateStr).toLocaleDateString(),
            "Total Revenue (PHP)": Number(daily[dateStr].toFixed(2)),
          }));
      }

      revenueExport.push({
        Total: "",
        "Total Revenue (PHP)": Number(grandTotal.toFixed(2)),
      });
      const revSheet = XLSX.utils.json_to_sheet(revenueExport);
      XLSX.utils.book_append_sheet(workbook, revSheet, `${dateRange} Revenue`);

      // --- SHEET 2: TOP PRODUCTS (POS within range) ---
      const productAgg = {};
      let totalUnits = 0;
      posData.forEach((p) => {
        const name = p.Inventory?.item_name || "Unknown";
        productAgg[name] = (productAgg[name] || 0) + p.quantity;
        totalUnits += p.quantity;
      });

      const topProductsExport = Object.keys(productAgg)
        .map((name) => ({
          "Product Name": name,
          "Units Sold": productAgg[name],
          "Market Share (%)":
            totalUnits > 0
              ? `${Math.round((productAgg[name] / totalUnits) * 100)}%`
              : "0%",
        }))
        .sort((a, b) => b["Units Sold"] - a["Units Sold"]);

      const topSheet = XLSX.utils.json_to_sheet(topProductsExport);
      XLSX.utils.book_append_sheet(
        workbook,
        topSheet,
        `${dateRange} Top Products`,
      );

      // --- SHEET 3: ACTIVITY LEDGER (Reservations in range) ---
      const { data: reservations } = await supabase
        .from("Reservation")
        .select(
          "id, created_at, status, quantity, user_id, Inventory(item_name, item_image), Users(email)",
        )
        .gte("created_at", startDate.toISOString())
        .lte("created_at", endDate.toISOString())
        .order("created_at", { ascending: false });

      const activityExport = (reservations || []).map((r) => ({
        Date: new Date(r.created_at).toLocaleDateString(),
        Time: new Date(r.created_at).toLocaleTimeString(),
        CustomerEmail: r.Users?.email || "",
        Product: r.Inventory?.item_name || "",
        Quantity: r.quantity || "",
        Status: r.status || "",
        Reference: `#RES-${String(r.id).slice(0, 4).toUpperCase()}`,
      }));

      const actSheet = XLSX.utils.json_to_sheet(activityExport);
      XLSX.utils.book_append_sheet(
        workbook,
        actSheet,
        `${dateRange} Activity Ledger`,
      );

      // --- SHEET 4: NEW INVENTORY (arrivals in range) ---
      const { data: arrivals } = await supabase
        .from("Inventory")
        .select("id, item_name, price, created_at")
        .gte("created_at", startDate.toISOString())
        .lte("created_at", endDate.toISOString())
        .order("created_at", { ascending: false });

      const inventoryExport = (arrivals || []).map((i) => ({
        "Item Name": i.item_name,
        Price: Number(i.price).toFixed(2),
        "Date Added": new Date(i.created_at).toLocaleDateString(),
      }));

      const invSheet = XLSX.utils.json_to_sheet(inventoryExport);
      XLSX.utils.book_append_sheet(
        workbook,
        invSheet,
        `${dateRange} New Inventory`,
      );

      // --- GENERATE DOWNLOAD ---
      const timestamp = new Date().toISOString().split("T")[0];
      XLSX.writeFile(
        workbook,
        `Alloycast_Dashboard_${dateRange.replace(/\s+/g, "_")}_Report_${timestamp}.xlsx`,
      );

      showToast("Multi-sheet business report exported!", "success");
    } catch (err) {
      console.error("Export failed:", err);
      showToast("Export failed. Check console for details.", "error");
    }
  };

  const handleActionClick = (res, newStatus) => {
    setConfirmModal({
      isOpen: true,
      reservationId: res.id,
      newStatus,
      customerEmail: res.customer_email,
      customerName: res.customer_name,
      productName: res.Inventory?.item_name,
    });
  };

  const statusUpdate = async (
    reservationId,
    newStatus,
    customerEmail,
    customerName,
    productName,
    reasonCancellation = "",
  ) => {
    // 1. Update Supabase
    const { error } = await supabase
      .from("Reservation")
      .update({ status: newStatus })
      .eq("id", reservationId);

    if (error) {
      showToast("Failed to update status", "error");
      return;
    }

    // 2. Send Email via EmailJS
    try {
      if (newStatus === "Approved") {
        await emailjs.send(
          "service_mu3qrbd",
          "template_uhrasxf",
          {
            to_email: customerEmail,
            customerName: customerName,
            productName: productName,
            status: newStatus,
            message:
              newStatus === "Approved"
                ? "Great news! Your order is approved. Please visit the store for pickup."
                : "Unfortunately, your reservation could not be accommodated.",
          },
          "3ilQZwBk_Cxjfohab", // Your Public Key
        );
        showToast("Order updated and email sent to customer!", "success");
      } else if (newStatus === "Declined") {
        const response = await fetch("/api/send-email", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            to_email: customerEmail,
            customerName: customerName,
            productName: productName,
            status: newStatus,
            reasonCancellation: reasonCancellation,
          }),
        });
        const result = await response.json();
        if (result.success) {
          showToast("Cancellation email sent to customer", "success");
        } else {
          throw new Error(result.error);
        }
      }
    } catch (err) {
      showToast("Status updated, but email failed to send.", "error");
    }

    // 3. Update local state
    setRecentActivities((prev) =>
      prev.map((res) =>
        res.id === reservationId ? { ...res, status: newStatus } : res,
      ),
    );
    setIsDetailsModalOpen(false);
  };

  // Functions to handle the Confirmation Modal buttons
  const handleConfirm = (reasonCancellation) => {
    const {
      reservationId,
      newStatus,
      customerEmail,
      customerName,
      productName,
    } = confirmModal;
    setConfirmModal({ ...confirmModal, isOpen: false });
    statusUpdate(
      reservationId,
      newStatus,
      customerEmail,
      customerName,
      productName,
      reasonCancellation,
    );
  };

  const handleCancel = () => {
    setConfirmModal({ ...confirmModal, isOpen: false });
  };

  return (
    <div className="bg-background  font-body min-h-screen overflow-x-hidden select-none">
      {/* --- Main Content Canvas --- */}
      <main className="pl-0 lg:pl-[var(--sidebar-width)] ml-5  pt-24 lg:pt-5 px-6 lg:px-8 pb-12 min-h-screen transition-all duration-300">
        {" "}
        {/* Header Section */}
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-8 gap-6 reveal-up">
          <div>
            <h3 className="text-4xl sm:text-5xl lg:text-6xl text-font-color font-black font-headline tracking-tighter uppercase italic leading-none">
              Admin Dashboard
            </h3>
          </div>
          <div className="w-full lg:w-auto">
            <button
              onClick={exportToExcel}
              className="w-full lg:w-auto bg-primary-container text-black/90 shadow-lg/30 px-6 py-3 rounded-lg text-sm font-headline font-bold uppercase tracking-widest flex items-center justify-center space-x-2 hover:scale-[1.02] transition-transform active:scale-95"
            >
              <span className="material-symbols-outlined text-sm">
                download
              </span>
              <span>Export Dashboard Data</span>
            </button>
          </div>
        </div>
        {/* KPI Bento Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <KPICard
            icon="bookmark_manager"
            label="Total Reservations"
            value={data.totalReservations.toLocaleString()}
            delay="0.1s"
            onClick={() => router.push("/admin/reservations")}
          />
          <KPICard
            icon="pending_actions"
            label="Pending Review"
            value={data.pendingReservations.toLocaleString()}
            onClick={() => router.push("/admin/reservations")}
          />
          <KPICard
            icon="payments"
            label="POS Revenue"
            value={`₱${totalRevenue.toLocaleString("en-US", {
              minimumFractionDigits: 2,
              maximumFractionDigits: 2,
            })}`}
            onClick={() => router.push("/admin/analytics")}
          />
          <KPICard
            icon="warning"
            label="Critical Stock"
            value={data.criticalStockCount.toString().padStart(2, "0")}
            trend={
              data.criticalStockCount > 0 ? "Urgent Restock" : "Enough Stock"
            }
            trendColor={
              data.criticalStockCount > 0
                ? "text-primary-container"
                : "text-green-500"
            }
            delay="0.4s"
            badge={data.criticalStockCount > 0 ? "Urgent" : null}
            onClick={() => setIsStockModalOpen(true)}
          />
        </div>
        {/* Primary Data Row */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          <div
            className="lg:col-span-2 bg-input-field p-4 rounded-lg border border-primary-container  text-white/90 shadow-lg/30 relative reveal-up"
            style={{ animationDelay: "0.5s" }}
          >
            {/* Updated Header Layout: Responsive stacking */}
            <div className="flex flex-col xl:flex-row xl:items-center justify-between mb-10 gap-8">
              {/* 1. Title */}
              <div className="flex items-center space-x-4">
                <div className="w-10 h-10 bg-primary-container rounded-lg flex items-center justify-center">
                  <span className="material-symbols-outlined text-secondary-container">
                    insights
                  </span>
                </div>
                <h4 className="text-xl font-black font-headline uppercase tracking-tighter italic text-white/90">
                  Revenue Analysis
                </h4>
              </div>

              {/* 2. Filter Buttons - Grid 2x2 on mobile, flex on desktop */}
              <div className="w-full xl:w-auto">
                <div className="grid grid-cols-2 2xl:flex items-center bg-secondary-container p-1 rounded-lg  gap-1">
                  {["Last 7 Days", "This Month", "Last Month", "Annual"].map(
                    (label) => (
                      <button
                        key={label}
                        onClick={() => setDateRange(label)}
                        className={`w-full xl:w-auto px-4 py-2 text-sm sm:text-xs font-headline font-black uppercase tracking-widest transition-all rounded-lg whitespace-nowrap ${
                          dateRange === label
                            ? "bg-primary-container text-black/90 shadow-lg"
                            : "text-white/90 opacity-80 hover:opacity-100 hover:bg-secondary-container/10"
                        }`}
                      >
                        {label}
                      </button>
                    ),
                  )}
                </div>
              </div>

              {/* 3. Total Revenue */}
              <div className="flex items-center space-x-3 bg-primary-container/10 px-5 py-3  rounded-lg w-full xl:w-auto justify-center xl:justify-start">
                <div className="w-2 h-2 bg-primary-container rounded-full shadow-[0_0_8px_rgba(248,228,8,0.5)] animate-pulse"></div>
                <div className="flex flex-col">
                  <span className="text-[9px] font-headline font-bold uppercase tracking-[0.2em] text-white/60 leading-none mb-1">
                    TOTAL REVENUE
                  </span>
                  <span className="text-xl font-black font-headline text-primary-container leading-none">
                    ₱
                    {totalRevenue.toLocaleString("en-US", {
                      minimumFractionDigits: 2,
                      maximumFractionDigits: 2,
                    })}
                  </span>
                </div>
              </div>
            </div>

            {/* Chart Area - Responsive Height */}
            <div className="h-[250px] sm:h-[300px] lg:h-[400px] w-full relative mt-4">
              {!revenueData ||
              revenueData.length === 0 ||
              totalRevenue === 0 ? (
                <div className="h-full w-full flex items-center justify-center text-white/60 uppercase font-black tracking-widest">
                  No available data on this category
                </div>
              ) : (
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart
                    data={revenueData}
                    margin={{ top: 10, right: 10, left: -20, bottom: 0 }}
                  >
                    <defs>
                      <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                        <stop
                          offset="5%"
                          stopColor="#22C55E"
                          stopOpacity={0.4}
                        />
                        <stop
                          offset="95%"
                          stopColor="#22C55E"
                          stopOpacity={0}
                        />
                      </linearGradient>
                    </defs>
                    <XAxis
                      dataKey="name"
                      stroke="#ffffff"
                      fontSize={12}
                      tickMargin={10}
                      axisLine={10}
                      tickLine={10}
                      opacity={1}
                    />
                    <YAxis
