                : reservation.status === "Declined" ||
                    reservation.status === "Cancelled"
                  ? "bg-red-500"
                  : "bg-secondary-container",

            img: reservation.Inventory?.item_image || "/logo.jpg",
          };
        });
        setReservationDB(mergedTables);
      }
    } catch (error) {
