"use client";
import React, { useState } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "../../lib/supabase/client";
import Scanner from "./Scanner";
import Toast from "./Toast";

const AddProductModal = ({ isOpen, onClose, onSuccess, inventory }) => {
  const [addFormData, setAddFormData] = useState({
    item_name: "",
    item_brand: "",
    category: "",
    price: 0,
    stock: 0,
    item_image: "",
    barcode: "",
  });
  const [preview, setPreview] = useState(null);
  const [scannerOpen, setScannerOpen] = useState(false);
  const [scannedBarCode, setScannedBarCode] = useState(null);
  const [cameraOpen, setCameraOpen] = useState(false);
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "error",
  });

  const supabase = createClient();
  const router = useRouter();
  const fileInputRef = React.useRef(null); // pang kuha ng image file
  const videoRef = React.useRef(null); // opens camera to capture image of product
  const canvasRef = React.useRef(null); // converts the video to img file

  // completely stops the camera
  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      // Loop through all active camera streams (tracks) and turn them off
      videoRef.current.srcObject.getTracks().forEach((track) => track.stop());
    }
    setCameraOpen(false);
  };

  // closes the camera when X button is clicked
  React.useEffect(() => {
    if (!isOpen) {
      stopCamera();
    }
    return () => {
      stopCamera();
    };
  }, [isOpen]);

  if (!isOpen) return null;

  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast((prev) => ({ ...prev, visible: false })), 4000);
  };

  const startCamera = async () => {
    setCameraOpen(true);
    try {
      // Request permission and access the rear camera ("environment")
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "environment" },
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream; // Feed the stream into the <video> tag
        videoRef.current.play(); // Start playing the video
      }
    } catch (err) {
      showToast("Error accessing camera: " + err.message, "error");
      setCameraOpen(false);
    }
  };

  const captureImage = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      // Match the canvas size to the actual video resolution
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      // "Draw" the current video frame onto the canvas
      const context = canvas.getContext("2d");
      context.drawImage(video, 0, 0, canvas.width, canvas.height);
      // Convert the drawn canvas into a Blob (raw data), then into a File
      canvas.toBlob(
        (blob) => {
          if (blob) {
            // We create a File object so it perfectly mimics a user uploading a file
            const file = new File([blob], `camera_capture_${Date.now()}.jpg`, {
              type: "image/jpeg",
            });
            setAddFormData((prev) => ({
              ...prev,
              item_image: file,
            }));
            setPreview(URL.createObjectURL(file));
            // / Show the preview thumbnail
            stopCamera();
            showToast("Item image captured successfully", "success");
          }
        },
        "image/jpeg",
        0.9, // 0.9 is the image quality (90%)
      );
    }
  };

  const getInputValue = (e) => {
    const { name, value, type, files } = e.target;
    // For file inputs, we need to take files[0], not value
    const finalValue = type === "file" ? files[0] : value;
    setAddFormData((prevAddFormData) => ({
      ...prevAddFormData,
      [name]: finalValue,
    }));

    // Handle preview for images
    if (type === "file" && files[0]) {
      setPreview(URL.createObjectURL(files[0]));
    }
  };

  // Input sanitization
  const sanitizeInput = (text) => {
    if (typeof text !== "string") return text;
    return text
      .trim()
      .replace(/<[^>]*>?/gm, "")
      .substring(0, 100);
  };

  const handelScannedBarCode = async (decodedText) => {
    setScannedBarCode(decodedText);
    setScannerOpen(false);
    console.log("Scanned Items: ", decodedText);

    try {
      const response = await fetch(`/api/barcode?upc=${decodedText}`);

      const result = await response.json();
      const item = result.items?.[0];

      if (item) {
        setAddFormData((prev) => ({
          ...prev,
          item_name: item.title || "",
        }));
        showToast("Product Scanned Successfully!", "success");
      } else {
        showToast("Product not found", "error");
      }
    } catch (error) {
      console.log(error);
    }
  };

  // function para mag-add product sa Inventory Table
  const addProduct = async (e) => {
    e.preventDefault();
    let imageUrl = ""; // para sa image string url

    //upload muna ung image sa Supabase Storage
    if (addFormData.item_image) {
      const file = addFormData.item_image; // mula sa addFormData state
      const fileExt = file.name.split(".").pop(); // pang extract ng file extension

      // image input sanitization
      const sanitizeImage = (file) => {
        const allowedExtensions = ["jpg", "jpeg", "png", "webp"];
        const allowedMimeTypes = ["image/jpeg", "image/png", "image/webp"];
        const maxSize = 25 * 1024 * 1024; // 2MB
        const fileExtension = file.name.split(".").pop().toLowerCase();
        if (
          !allowedExtensions.includes(fileExtension) ||
          !allowedMimeTypes.includes(file.type)
        ) {
          throw new Error(
            "Invalid file type. Only JPG, PNG, and WEBP are allowed.",
          );
        }
        if (file.size > maxSize) {
          throw new Error("File is too large. Maximum size is 20MB.");
        }
        const safeName = file.name.replace(/[^a-z0-9.]/gi, "_").toLowerCase();

        return safeName;
      };
      if (file) {
        try {
          const safeFileName = sanitizeImage(file);
          const filePath = `${Date.now()}_${safeFileName}`;
          const { data: uploadData, error: uploadError } =
            await supabase.storage //insert sa Supabase Storage Bucket
              .from("Inventory") // Inventory Table
              .upload(filePath, file); // img

          if (uploadError) {
            showToast("Error uploading image: " + uploadError.message);
            return;
          }

          const {
            data: { publicUrl },
          } = supabase.storage
            .from("Inventory")
            .getPublicUrl(filePath, file, { upsert: true });

          imageUrl = publicUrl;
        } catch (err) {
          showToast(err.message, "error");
          return;
        }
      }
    }

    const sanitizedInput = {
      item_name: sanitizeInput(addFormData.item_name),
      brand: addFormData.item_brand, // These come from <select>, so they are safer
      category: addFormData.category,
      price: Math.abs(parseFloat(addFormData.price)) || 0, // Ensure price is positive
      stock: Math.abs(parseInt(addFormData.stock)) || 0, // Ensure stock is positive
    };

    const { data, error } = await supabase.from("Inventory").insert([
      //upload ung inventory sa Inventory Table
      {
        item_name: sanitizedInput.item_name,
        brand: sanitizedInput.brand,
        category: sanitizedInput.category,
        price: sanitizedInput.price,
        stock: sanitizedInput.stock,
        item_image: imageUrl,
        barcode: scannedBarCode,
      },
    ]);

    if (error) {
      alert("SUPABASE ERROR:", error.message);
      showToast("Error adding product to Inventory");
    } else {
      showToast("Product Added!", "success");
      setAddFormData({
        item_name: "",
        item_brand: "",
        category: "",
        price: 0,
        stock: 0,
        item_image: " ",
        barcode: "",
      });

      setTimeout(() => {
        if (onSuccess) onSuccess(); // refresh agad
        onClose();
      }, 3000);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div
        className="absolute inset-0 bg-background/80 backdrop-blur-sm animate-fade-in"
        onClick={onClose}
      />
      <form
        onSubmit={addProduct}
        className="relative w-full max-w-3xl bg-background rounded-lg shadow-[0_0_100px_rgba(0,0,0,1)]  animate-slide-in-up flex flex-col max-h-[90vh]"
      >
        <header className="p-6 sm:p-8 lg:p-10 border-b border-white/[0.03] flex flex-col sm:flex-row items-start sm:items-center justify-between shrink-0 gap-6">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 sm:w-12 sm:h-12 bg-secondary-container border border-secondary-container/20 flex items-center justify-center rounded-lg">
              <span className="material-symbols-outlined text-primary-container text-xl sm:text-2xl">
                add_box
              </span>
            </div>
            <div>
              <h4 className="text-2xl sm:text-3xl text-font-color font-black font-headline uppercase tracking-tighter italic leading-none">
                ADD PRODUCT
              </h4>
              <p className="text-xs sm:text-sm font-headline font-bold uppercase tracking-[0.2em] text-font-color mt-1">
                NEW INVENTORY ENTRY
              </p>
            </div>
          </div>
          <div className="flex w-full sm:w-auto gap-4 items-center justify-between sm:justify-end">
            <button
              type="button"
              onClick={() => setScannerOpen(true)}
              className="flex-1 sm:flex-none px-6 sm:px-8 h-12 bg-primary-container rounded-lg text-xs sm:text-sm text-black font-black font-headline uppercase tracking-[0.2em] sm:tracking-[0.3em] hover:scale-105 active:scale-95 transition-all shadow-lg/30 hover:shadow-primary-container/20 flex items-center justify-center gap-2"
            >
              <span className="material-symbols-outlined text-lg">
                qr_code_scanner
              </span>
              <span>SCAN</span>
            </button>
            <button
              type="button"
              onClick={onClose}
              className="w-12 h-12 flex items-center justify-center border border-white/5 hover:bg-white/5 rounded-lg transition-colors group"
            >
              <span className="material-symbols-outlined text-font-color  group-hover:rotate-90 transition-all text-xl font-light">
                close
              </span>
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 lg:p-10 space-y-8 custom-scrollbar">
