              ITEM NAME
            </label>
            <input
              name="item_name"
              type="text"
              value={addFormData.item_name}
              required
              placeholder="e.g. Ferrari F40"
              className="w-full bg-input-field border border-white/[0.03] rounded-lg h-14 px-6 text-md font-headline font-bold  tracking-widest focus:border-primary-container outline-none transition-all duration-300 text-white placeholder:text-white/10"
              onChange={getInputValue}
            />
          </div>

          {/* Brand & Category */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
            <div className="space-y-3">
              <label className="text-sm text-font-color font-headline font-bold uppercase tracking-[0.3em]  inline-block border-l-2 border-secondary-container pl-2">
                BRAND
              </label>
              <select
                id="item_brand"
                name="item_brand"
                type="text"
                value={addFormData.item_brand}
                required
                className="w-full bg-input-field border border-white/[0.03] rounded-lg h-14 px-6 text-md font-headline font-bold  tracking-widest focus:border-primary-container outline-none transition-all duration-300 text-white placeholder:text-white/10"
                onChange={getInputValue}
              >
                <option value="" disabled hidden>
                  Brand
                </option>
                <option value="Hot Wheels">Hot Wheels</option>
                <option value="Tomica">Tomica</option>
                <option value="Majorette">Majorette</option>
                <option value="Auto World">Auto World</option>
                <option value="Mini GT">Mini GT</option>
                <option value="Bburago">Bburago</option>
                <option value="Maisto">Maisto</option>
                <option value="M2">M2</option>
                <option value="Jada">Jada</option>
                <option value="AutoWorld">Auto World</option>
                <option value="Nascar">Nascar</option>
                <option value="Others">Others...</option>
              </select>
            </div>
            <div className="space-y-3">
              <label className="text-sm text-font-color font-headline font-bold uppercase tracking-[0.3em]  inline-block border-l-2 border-secondary-container pl-2">
                CATEGORY
              </label>
              <select
                id="category"
                name="category"
                type="text"
                value={addFormData.category}
                required
                className="w-full bg-input-field border border-white/[0.03] rounded-lg h-14 px-6 text-md font-headline font-bold  tracking-widest focus:border-primary-container outline-none transition-all duration-300 text-white placeholder:text-white/10"
                onChange={getInputValue}
              >
                <option value="" disabled hidden>
                  Series
                </option>
                <option value="Mainline">Mainline Series</option>
                <option value="Special">Special Series</option>
                <option value="Premium">Premium Series</option>
                <option value="Chase">Chase Series</option>
                <option value="Others">Others...</option>
              </select>
            </div>
          </div>

