            <div className="space-y-3">
              <label className="text-sm text-font-color font-headline font-bold uppercase tracking-[0.3em]  inline-block border-l-2 border-secondary-container pl-2">
                PRICE (₱)
              </label>
              <input
                name="price"
                type="number"
                value={addFormData.price}
                step="0.01"
                required
                placeholder="0.00"
                className="w-full bg-input-field border border-white/[0.03] rounded-lg h-14 px-6 text-md font-headline font-bold  tracking-widest outline-none focus:border-primary-container transition-all text-white placeholder:text-white/70"
                onChange={getInputValue}
              />
            </div>
            <div className="space-y-3">
              <label className="text-sm text-font-color font-headline font-bold uppercase tracking-[0.3em]  inline-block border-l-2 border-secondary-container pl-2">
                STOCK
              </label>
              <input
                name="stock"
                type="number"
                required
                placeholder="0"
                className="w-full bg-input-field border border-white/[0.03] rounded-lg h-14 px-6 text-md font-headline font-bold  tracking-widest outline-none focus:border-primary-container transition-all text-white placeholder:text-white/70"
                onChange={getInputValue}
              />
            </div>
          </div>

          {/* Item Image */}
          <div className="space-y-3">
            <div className="flex justify-between items-center">
              <label className="text-sm text-font-color font-headline font-bold uppercase tracking-[0.3em] inline-block border-l-2 border-secondary-container pl-2">
                ITEM IMAGE
              </label>
              <button
                type="button"
                onClick={startCamera}
                className="flex items-center gap-2 px-3 py-1.5 sm:px-4 sm:py-2 bg-secondary-container hover:bg-secondary-container/80 text-white text-[10px] sm:text-xs font-bold uppercase tracking-wider rounded-lg transition-colors shadow-lg/30"
              >
                <span className="material-symbols-outlined text-sm sm:text-base">
                  photo_camera
                </span>
                OPEN CAMERA
              </button>
            </div>
            <div
              onClick={() => fileInputRef.current.click()}
              className="w-full h-48 bg-input-field border border-dashed border-white/10 rounded-lg flex flex-col items-center justify-center group cursor-pointer hover:border-primary-container transition-all duration-500 rounded-[2px] relative overflow-hidden"
            >
              <input
                type="file"
                name="item_image"
                ref={fileInputRef}
                className="hidden rounded-lg"
                accept="image/*"
                onChange={getInputValue}
              />
              {preview ? (
                <img
                  src={preview}
                  alt="Preview"
                  className="absolute inset-0 w-full h-full object-cover opacity-40 group-hover:opacity-60 transition-opacity"
                />
              ) : (
                <div className="relative z-10 flex flex-col items-center">
                  <span className="material-symbols-outlined text-4xl font-light opacity-60 mb-4 group-hover:text-primary-container group-hover:opacity-100 transition-all duration-500">
                    add_photo_alternate
                  </span>
                  <p className="text-[12px] font-headline font-bold uppercase tracking-[0.3em]">
                    <span className="opacity-70 text-white/90 text-lg">
                      DRAG & DROP OR
                    </span>{" "}
                    <span className="text-primary-container text-lg group-hover:text-primary-container transition-colors">
                      BROWSE
                    </span>
                  </p>
                  <p className="text-xs text-white/90 mt-3 uppercase tracking-[0.1em]">
                    High-res PNG/JPG preferred.
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>

        <footer className="p-6 sm:p-8 border-t border-secondary-container flex flex-col sm:flex-row justify-end gap-3 sm:gap-4 bg-background rounded-lg  shrink-0">
          <button
            type="button"
            onClick={onClose}
            className="w-full sm:w-auto px-8 h-12 shadow-lg/30 bg-secondary-container hover:scale-105 rounded-lg text-xs sm:text-sm text-white/90 font-black font-headline uppercase tracking-[0.2em] sm:tracking-[0.3em]  transition-all"
          >
            CANCEL
          </button>

          <button
            type="submit"
            className="w-full sm:w-auto px-8 h-12 bg-primary-container rounded-lg text-xs sm:text-sm text-black font-black font-headline uppercase tracking-[0.2em] sm:tracking-[0.3em] hover:scale-105 active:scale-95 transition-all shadow-lg/30 hover:shadow-secondary-container/20"
          >
            ADD TO INVENTORY
          </button>
        </footer>
      </form>
      <Toast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />
      {cameraOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm animate-fade-in">
          <div className="relative w-full max-w-lg bg-background rounded-lg shadow-[0_0_50px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col">
            <div className="p-4 flex justify-between items-center border-b border-white/10">
              <h4 className="text-lg text-white font-bold font-headline uppercase tracking-wider">
                Take Photo
              </h4>
              <button
                type="button"
                onClick={stopCamera}
                className="w-8 h-8 flex items-center justify-center bg-white/10 hover:bg-white/20 rounded-full transition-colors"
              >
                <span className="material-symbols-outlined text-white text-sm">
                  close
                </span>
              </button>
            </div>
            <div className="relative bg-black w-full aspect-square flex items-center justify-center">
              <video
                ref={videoRef}
                className="w-full h-full object-cover"
                autoPlay
                playsInline
                muted
              />
              <canvas ref={canvasRef} className="hidden" />
            </div>
            <div className="p-6 flex justify-center bg-background border-t border-white/10">
              <button
                type="button"
                onClick={captureImage}
                className="w-16 h-16 rounded-full border-4 border-primary-container bg-white/10 hover:bg-primary-container transition-colors flex items-center justify-center"
              >
                <div className="w-12 h-12 rounded-full bg-white transition-all scale-90 hover:scale-100" />
              </button>
            </div>
          </div>
        </div>
      )}
      <Scanner
        scannerOpen={scannerOpen}
        scannerClose={() => setScannerOpen(false)}
        onScan={handelScannedBarCode}
      />
    </div>
  );
};

