"use client";

import { useEffect, useState } from "react";
import dynamic from "next/dynamic";

const DynamicToast = dynamic(() => import("./Toast"));

export default function POSModal({
  isOpen,
  isClose,
  selectedItem,
  onPurchase,
}) {
  const [userName, setUserName] = useState("");
  const [emailAddr, setEmailAddr] = useState("");
  const [quantity, setQuantity] = useState(1);
  const [stockCheck, setStockCheck] = useState(false);
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "error",
  });

  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast((prev) => ({ ...prev, visible: false })), 4000);
  };

  const handleQuantityChange = (e) => {
    const value = e.target.value;
    if (value === "") {
      setQuantity("");
    } else {
      const parsed = parseInt(value, 10);
      if (!isNaN(parsed)) {
        if (parsed > selectedItem?.stock) {
          setQuantity(selectedItem.stock);
          showToast(
            `Quantity capped at maximum available stock (${selectedItem.stock})`,
            "error",
          );
        } else if (parsed < 1) {
          setQuantity(1);
        } else {
          setQuantity(parsed);
        }
      }
    }
  };

  const handleConfirm = () => {
    const parsedQuantity = parseInt(quantity, 10);
    if (isNaN(parsedQuantity) || parsedQuantity < 1) {
      showToast("Please enter a valid quantity of at least 1.", "error");
      return;
    }
    if (parsedQuantity > selectedItem?.stock) {
      showToast(
        `Cannot purchase more than the available stock of ${selectedItem.stock} units.`,
        "error",
      );
      return;
    }

    onPurchase({ userName, emailAddr, quantity: parsedQuantity });
    setUserName("");
    setEmailAddr("");
    setQuantity(1);
  };

  useEffect(() => {
    if (selectedItem?.stock !== undefined && quantity > selectedItem.stock) {
      setStockCheck(true); // over stock limit
    } else {
      setStockCheck(false);
    }
  }, [quantity, selectedItem]);
  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-background/80"
      onClick={isClose}
    >
      <div
        className="bg-background shadow-lg/30  rounded-lg p-6 max-w-md w-full mx-4"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex flex-col gap-4">
          <h1 className="text-3xl font-black font-headline uppercase tracking-tight text-font-color">
            {selectedItem?.item_name}
          </h1>
          <div className="flex flex-col gap-1">
            <p className="text-lg font-bold text-font-color">
              Price:{" "}
              <span className="text-font-color">₱{selectedItem?.price}</span>
            </p>
            <p className="text-lg font-bold text-font-color">
              <label htmlFor="">Quantity: </label>
              <input
                type="number"
                placeholder="Enter Quantity"
                className="bg-input-field text-white/90 p-2 rounded-lg"
                value={quantity}
                onChange={handleQuantityChange}
              />

