              onChange={(e) => setUserName(e.target.value)}
            />

            <label className="text-font-color text-lg mt-2">
              Customer Email (Optional):
            </label>
            <input
              type="email"
              placeholder="johndoe@gmail.com"
              className="bg-input-field text-white/90 p-2 rounded-lg"
              value={emailAddr}
              onChange={(e) => setEmailAddr(e.target.value)}
            />
          </div>
          <div className="flex gap-3 mt-4">
            <button
              onClick={isClose}
              className="flex-1 py-2 shadow-lg/30 bg-secondary-container rounded-lg text-white text-md font-bold hover:scale-105 transition-all"
            >
              Cancel
            </button>

            <button
              className="flex-1 py-2 shadow-lg/30 bg-primary-container rounded-lg text-black text-md font-bold hover:scale-105 transition-all"
              onClick={handleConfirm}
            >
              Confirm Purchase
            </button>
          </div>
        </div>
      </div>
      <DynamicToast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />
    </div>
  );
}

"use client";
import { useState, useEffect, useRef } from "react";
import { Html5Qrcode } from "html5-qrcode";
import Toast from "./Toast";

export default function Scanner({ scannerOpen, scannerClose, onScan }) {
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "error",
  });
  const scannerRef = useRef(null);

  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast((prev) => ({ ...prev, visible: false })), 4000);
  };

  useEffect(() => {
    if (!scannerOpen) return;

    // barcode
    const html5QrCode = new Html5Qrcode("reader");
    scannerRef.current = html5QrCode;

    const config = {
      fps: 10,
      qrbox: { width: 250, height: 250 },
      aspectRatio: 1.0,
    };

    //scanning
    const startScanner = async () => {
      try {
        await html5QrCode.start(
          { facingMode: "environment" },
          config,
          (decodedText) => {
            if (onScan) onScan(decodedText);
          },
        );
      } catch (err) {
        console.error("Scanner error:", err);
        showToast("Scanner error. Please try again.", "error");
      }
    };

    startScanner();

    //fail
    return () => {
      if (scannerRef.current && scannerRef.current.isScanning) {
        scannerRef.current
          .stop()
          .then(() => scannerRef.current.clear())
          .catch((err) => showToast("Failed to stop scanner:", "error"));
      }
    };
  }, [scannerOpen, onScan]);

  if (!scannerOpen) return null;

  return (
    <div
      className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-4 sm:p-8"
      onClick={scannerClose}
    >
      <div
        className="relative w-full max-w-md aspect-square bg-zinc-950 rounded-3xl overflow-hidden border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)] flex flex-col items-center justify-center"
        onClick={(e) => e.stopPropagation()}
      >
        {/* scanner camera */}
        <div id="reader" className="w-full h-full [&>video]:object-cover"></div>

        {/* Scanning Overlay */}
        <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-end pb-12 sm:pb-16">
          <div className="px-6 py-2 bg-white/5 border border-white/10 rounded-full backdrop-blur-xl">
            <p className="text-[10px] sm:text-[12px] font-headline font-black uppercase tracking-[0.2em] sm:tracking-[0.3em] text-white/70">
              Align Barcode in Frame
            </p>
          </div>
        </div>

        {/* Header/Close */}
        <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-30">
          <div className="flex items-center gap-2"></div>
          <button
            onClick={scannerClose}
            className="w-10 h-10 flex items-center justify-center bg-white/5 hover:bg-white/10 text-white rounded-full transition-all border border-white/5 active:scale-90"
          >
            <span className="material-symbols-outlined text-xl">close</span>
          </button>
        </div>
      </div>
      <Toast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />
    </div>
  );
}

"use client";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";

export default function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  // useEffect ensures the component only renders on the client
  // to prevent hydration mismatch errors
  useEffect(() => setMounted(true), []);
  if (!mounted) return null;

  return (
    <button
      onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
      className="fixed bottom-8 right-8 w-12 h-12 rounded-full bg-primary-container text-black shadow-lg/30 transition-transform active:scale-95 z-50 font-black italic uppercase tracking-widest text-[10px] flex items-center justify-center"
      aria-label="Toggle Theme"
    >
      <span className="material-symbols-outlined text-[20px] transition-transform duration-500 group-hover:rotate-12 leading-none">
        {theme === "dark" ? "light_mode" : "dark_mode"}
      </span>
    </button>
  );
}

