const DynamicToast = dynamic(() => import("../../../components/Toast"));
const DynamicForgotPasswordModal = dynamic(
  () => import("../../../components/ForgotPasswordModal"),
  { ssr: false },
);
const DynamicNewPasswordModal = dynamic(
  () => import("../../../components/NewPasswordModal"),
  { ssr: false },
);

function LoginContent() {
  const [showPassword, setShowPassword] = useState(false);
  const [loginForm, setLoginForm] = useState({
    email: "",
    password: "",
  });
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "error",
  });
  const [isForgotOpen, setIsForgotOpen] = useState(false);
  const [isNewOpen, setIsNewOpen] = useState(false);
  const timeoutRef = useRef(null);

  const router = useRouter();
  const searchParams = useSearchParams(); // for capturing clicked product url and id
  const supabase = createClient();

  // const redirectTo = searchParams.get("redirectTo") || "/customer/dashboard"; // gets the redirect path from capturedCurrentPath in productDetail

  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ ...toast, visible: false }), 4000);
  };

  // pangkuha ng input
  const getInputValue = (e) => {
    const { name, value } = e.target;
    setLoginForm((prevLoginForm) => ({
      ...prevLoginForm,
      [name]: value,
    }));
  };

  const checkEmail = async () => {
    try {
      const { count } = await supabase
        .from("Users")
        .select("*", { count: "exact" })
        .eq("email", loginForm.email.trim().toLowerCase());

      if (!count) {
        showToast("Email Not Found", "error");
      } else {
        setIsForgotOpen(true);
      }
    } catch (error) {
      console.log(error);
    }
  };

  const inputSanitizerFunction = () => {
    // panglinis ng email input
    const sanitizedForm = {
      ...loginForm,
      email: loginForm.email.trim().toLowerCase(),
    };

    // para icheck ung email format
    const emailFormat = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    // kailangan may symbol na "@"
    if (!emailFormat.test(sanitizedForm.email)) {
      return { isValid: false, message: "Invalid email format!" };
    }

    // kung ok lahat
    return { isValid: true, data: sanitizedForm };
  };

  const loginAccount = async (e) => {
    e.preventDefault();
    const formValidation = inputSanitizerFunction();
    if (!formValidation.isValid) {
      return showToast(formValidation.message);
    }

    const sanitizedData = formValidation.data;
    // gagamit na tayo ng supabase auth para sa login
    const { data, error } = await supabase.auth.signInWithPassword({
      email: sanitizedData.email, // kukunin email sa supabase Auth
      password: sanitizedData.password, // kukunin password sa supabase Auth
    });

    // pang check kung naverify na email o hindi
    if (error) {
      if (error.message.includes("Email not verified")) {
        return showToast(
          "Please verify your email before logging in!",
          "error",
        );
      }
      // kung mali email o password
      return showToast("Invalid Email or Password", "error");
    }

    if (!error) {
      const redirectTo = searchParams.get("redirectTo"); // kinukuha ung specific productDetail url (if meron)
      const destination = redirectTo || "/customer/account"; // kung meron, balik, kung wla, punta sa account
      showToast("Login Successful", "success");
      const id = setTimeout(() => {
        if (typeof window !== "undefined" && router && router.push) {
          router.push(destination); // redirects back to clicked productDetail
        }
      }, 1500);
      timeoutRef.current = id;
    } else {
      showToast(error.message, "error");
    }
  };

  // pang resend ng email verification
  const resendVerification = async () => {
    if (!loginForm.email) {
      return showToast("Please enter your email address first");
    }

    // isesend nito email verification sa gmail
    const { error } = await supabase.auth.resend({
      type: "signup",
      email: loginForm.email.trim().toLowerCase(),
      options: {
        emailRedirectTo: `${window.location.origin}/customer/auth/login`, // direct url kapag clinick email verification
      },
    });

    // pang check ng email verification resend
    if (error) {
      showToast(error.message);
    } else {
    }
  };

  const googleLogin = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: `${window.location.origin}/customer/auth/callback`,
        data: {
          is_admin: false,
        },
      },
    });

    if (error) {
      showToast(error.message);
    }
  };

  return (
    <div className="bg-background font-body text-on-surface min-h-screen flex items-center justify-center p-6 radial-brand">
      <DynamicToast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />
      <div className="max-w-4xl w-full grid grid-cols-1 md:grid-cols-2 bg-surface-container-high rounded-lg  overflow-hidden  shadow-lg/30 animate-fade-in">
        {/* Left Side: Branding/Visual */}
        <div className="relative hidden md:flex flex-col justify-between p-12 bg-black/80 text-white overflow-hidden">
          <div className="relative z-10">
            <h1 className="font-headline font-black text-4xl uppercase text-primary-container italic leading-none mb-4">
              Join the Hunt
            </h1>
            <p className="text-sm font-light uppercase tracking-widest opacity-80">
              The premier destination for elite diecast collectors.
            </p>
          </div>

          <div className="absolute -bottom-10 -right-20 w-[150%] opacity-20 pointer-events-none transform rotate-[-15deg]">
            <img
              alt="Car Silhouette"
              src="https://lh3.googleusercontent.com/aida-public/AB6AXuBL-AWm0406EG-1UZke8iuF1oZxcY65Vq6dc_9-A1GnFbAoiFAWnkMBVZgKMgaVRrrRUJYiw4nqzaDQd1xGgpwmcWvsEgj79XUUyMY5S2nZYlyPKfUOAWjiQ526D-dlyERFA5g4vM428anIhTgnebUse3SrzDJ-KFXe1uL4dTXtd2m6zn7W9gdZTxRKoEkXLyJSbUtC_04soQqG8Y9gtrtxozmtOzC2Dn_cxQRGR3D-A3F6oSplCvPXJHKZHEGE26GEuAPJ9owfaUc"
            />
          </div>

          <div className="relative z-10 flex items-center gap-2 text-primary-container">
            <span className="material-symbols-outlined">flare</span>
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">
              Diecast Vault established 2026
            </span>
          </div>
        </div>

        {/* Right Side: Form */}
        <div className="p-8 md:p-12 flex flex-col justify-center bg-secondary-container">
          <div className="mb-8">
            <h2 className="text-2xl font-headline text-primary-container uppercase italic mb-2">
              LOGIN YOUR ACCOUNT
            </h2>
            <p className="text-sm text-white/90 uppercase tracking-widest">
              To order the product you want
            </p>
          </div>

          <form className="space-y-6" onSubmit={loginAccount}>
            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                Email Address
              </label>
              <input
                type="email"
                placeholder="hello@gmail.com..."
                className="w-full bg-input-field dark:border-b dark:border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                name="email"
                value={loginForm.email}
                onChange={getInputValue}
              />
            </div>
            <div className="relative">
              <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                Password
              </label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="••••••••"
                  className="w-full bg-input-field dark:border-b dark:border-primary-container  rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight pr-12"
                  name="password"
                  value={loginForm.password}
                  onChange={getInputValue}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-3 text-[#A8A8A0] hover:text-white transition-colors"
                >
                  <span className="material-symbols-outlined text-md">
                    {showPassword ? "visibility" : "visibility_off"}
                  </span>
                </button>
              </div>
            </div>
            <p className="text-xs text-white/90 uppercase tracking-widest text-center">
              Didn&apos;t receive the email?{" "}
              <button
                type="button"
                onClick={resendVerification}
                className="text-primary-container hover:underline italic font-bold uppercase cursor-pointer"
              >
                Resend Link
              </button>
            </p>
            <div className="flex justify-end">
              <button
                type="button"
                onClick={() => checkEmail()}
                className=" text-blue-400   hover:underline text-xs drop-shadow-lg/30 italic font-bold uppercase cursor-pointer"
              >
                Forgot Password?
              </button>
            </div>
            <button
              type="button"
              className="w-full flex items-center justify-center gap-3 shadow-lg/30  bg-white hover:scale-105 transition-all text-black font-bold py-3 px-4 rounded-lg  mb-6 border border-gray-300"
              onClick={googleLogin}
            >
              <img
                src="https://img.icons8.com/?size=100&id=17949&format=png&color=000000"
                alt="Google Logo"
                className="w-5 h-5"
              />
              <span className="uppercase text-xs tracking-widest font-black">
                Sign in with Google
              </span>
            </button>

            <button className="w-full bg-primary-container shadow-lg/30 rounded-lg text-black/90 py-3 px-4  font-headline font-black uppercase tracking-[0.2em] text-sm hover:scale-105  transition-all transform active:scale-[0.98]">
              LOGIN
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-white/5 flex flex-col gap-4">
            <p className="text-xs text-white/90 uppercase tracking-widest text-center">
              Don&apos;t have an account?{" "}
              <Link
                href="/customer/auth/register"
                className="text-primary-container hover:underline italic font-bold"
              >
                SIGN UP
              </Link>
            </p>
          </div>
        </div>
      </div>
      <DynamicForgotPasswordModal
        isOpen={isForgotOpen}
        onClose={() => setIsForgotOpen(false)}
        onSubmit={() => {
          setIsForgotOpen(false);
          setIsNewOpen(true);
        }}
      />

      <DynamicNewPasswordModal
        isOpen={isNewOpen}
        onClose={() => setIsNewOpen(false)}
        onSubmit={() => setIsNewOpen(false)}
      />
    </div>
  );
}

export default function LoginPage() {
  return (
    <Suspense fallback={null}>
      <LoginContent />
    </Suspense>
  );
}

"use client";
import React from "react";
import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import Toast from "../../../components/Toast";
import TermsModal from "../../../components/TermsModal";
import DataPrivacyModal from "../../../components/DataPrivacyModal";
import { createClient } from "../../../../lib/supabase/client";
import dynamic from "next/dynamic";

const DynamicToast = dynamic(() => import("../../../components/Toast"), {
  ssr: false,
});

const DynamicTermsModal = dynamic(
  () => import("../../../components/TermsModal"),
  {
    ssr: false,
  },
);

const DynamicDataPrivacyModal = dynamic(
  () => import("../../../components/DataPrivacyModal"),
  {
    ssr: false,
  },
);
export default function RegisterPage() {
  const supabase = createClient();
  const router = useRouter(); // pang navigate to sa login page kung successfull na login
  // dto muna mastore mga input fields bago mapunta sa Users at Customers Table
  const [accountForm, setAccountForm] = useState({
    firstName: "",
    lastName: "",
    email: "",
    gender: "",
    dob: "",
    password: "",
    confirmPassword: "",
  });

  // UI States
  const [showPassword, setShowPassword] = useState(false); // eye toggle para makita password
  const [showConfirmPassword, setShowConfirmPassword] = useState(false); // eye toggle para makita confirmPassword
  const [isAgreed, setIsAgreed] = useState(false); // Agreement checkbox state
  const [isPrivacyAgreed, setIsPrivacyAgreed] = useState(false); // Privacy agreement state
  const [showTermsModal, setShowTermsModal] = useState(false); // Terms Modal visibility state
  const [showPrivacyModal, setShowPrivacyModal] = useState(false); // Privacy Modal state
  const [toast, setToast] = useState({
    // toast notification (gawa ni AI) hehehe
    visible: false,
    message: "",
    type: "error",
  });

  function getRandomString(n) {
    const characters = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    let randomString = "";
    for (let i = 0; i < n; i++) {
      const index = Math.floor(Math.random() * characters.length);
      randomString += characters[index];
    }
    return randomString;
  }

  // Function to show toast (gawa ni AI)
  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast((prev) => ({ ...prev, visible: false })), 4000);
  };

  // pangkuha ng input value bawat fields at pangupdate ng accountForm useState
  const getInputValue = (e) => {
    const { name, value } = e.target; // pange extract ng: e.target.value at name="" sa mga inputs
    setAccountForm((prevAccountForm) => ({
      // lumang accountForm (walang value)
      ...prevAccountForm, // kopya ng bagong accountForm (may values)
      [name]: value, // [name] = key sa bawat input fields (name="") para malaman ang value
    }));
  };

  // INPUT SANITIZATION
  const inputSanitizerFunction = () => {
    if (
      !accountForm.firstName ||
      !accountForm.lastName ||
      !accountForm.email ||
      !accountForm.gender ||
      !accountForm.dob ||
      !accountForm.password ||
      !accountForm.confirmPassword
    ) {
      return { isValid: false, message: "Please fill in all fields" };
    }
    // panglinis ng input sa firstname, lastname at email
    const sanitizeForm = {
      ...accountForm, // kopya ng accountForm={} para d magalaw ung original na accountForm
      firstName: accountForm.firstName.trim(),
      lastName: accountForm.lastName.trim(),
      email: accountForm.email.trim().toLowerCase(),
    };

    // pang check ng password length (min = 8)
    if (sanitizeForm.password.length < 8) {
      return {
        isValid: false,
        message: "Password must be at least 8 characters!",
      };
    }

    // pangcheck ng symbols sa password field
    const passwordSymbols = /[!@#$%^&*(),.?":{}|<>]/;
    if (!passwordSymbols.test(sanitizeForm.password)) {
      // kailangan gumamit ng symbols sa password
      return {
        isValid: false,
        message: "Password must contain at least one symbol (!@#$ etc.)",
      };
    }

    // pangkumpara ng password vs confirmPassword
    if (sanitizeForm.password !== sanitizeForm.confirmPassword) {
      return { isValid: false, message: "Passwords do not match!" };
    }

    // kung ok lahat ng fields
    return { isValid: true, data: sanitizeForm };
  };

  // ito ung function para maregister sa Users table muna
  const registerAccount = async (e) => {
    e.preventDefault(); // para maiwasan marefresh ung page kapag nagsubmit

    const formValidation = inputSanitizerFunction(); // call ng inputSanitizerFunction()
    if (!formValidation.isValid) {
      // kung hindi nakapasa sa input sanitization
      return showToast(formValidation.message); // return alert para mag stop ung execution ng buong functions
    }

    const sanitizedData = formValidation.data;

    // pang check if my kaparehas na email nakasatored sa Users Table
    const { data: existingEmail } = await supabase
      .from("Users")
      .select("email") // select email column
      .eq("email", sanitizedData.email) // pang check if may kaparehas nang email
      .maybeSingle(); // pang check kung may kaparehas na email KAHIT ISA

    if (existingEmail) {
      return showToast("This email is already registered");
    }

    // ok so binago ko na ung pag request kay supabase
    // gagamit na ito ng supabase auth at Users Table
    const { data, error } = await supabase.auth.signUp({
      // supabase Auth sign up
      email: sanitizedData.email, // store sa supabase auth at Users Table
      password: sanitizedData.password, // store sa supabase auth at Users Table
      options: {
        data: {
          first_name: sanitizedData.firstName, // store sa Customers Table
          last_name: sanitizedData.lastName, // store sa Customers Table
          gender: sanitizedData.gender, // store sa Customers Table
          dob: sanitizedData.dob, // store sa Customers Table
          is_admin: false, // matik false para Customers
          reset: getRandomString(5),
        },
      },
    });

    if (error) {
      showToast(error.message);
    } else {
      showToast(
        "Registration Success! Please check your email to verify your account.",
        "success",
      );
      setTimeout(() => {
        router.push("/customer/auth/login");
      }, 1500);
    }
  };

  const googleSignUp = async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: `${window.location.origin}/customer/auth/callback`,
        data: {
          is_admin: false,
        },
      },
    });

    if (error) {
      showToast(error.message);
    }
  };

  return (
    <div className="bg-background font-body text-on-surface min-h-screen flex items-center justify-center p-6 radial-brand relative overflow-x-hidden">
      {/* Reusable Toast Notification */}
      <DynamicToast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />

      {/* Terms of Service Modal */}
      <DynamicTermsModal
        isOpen={showTermsModal}
        onClose={() => setShowTermsModal(false)}
        onAgree={() => {
          setIsAgreed(true);
          setShowTermsModal(false);
        }}
      />

      {/* Data Privacy Modal */}
      <DynamicDataPrivacyModal
        isOpen={showPrivacyModal}
        onClose={() => setShowPrivacyModal(false)}
        onAgree={() => {
          setIsPrivacyAgreed(true);
          setShowPrivacyModal(false);
        }}
      />

      <div className="max-w-4xl min-h-screen w-full grid grid-cols-1 md:grid-cols-2 bg-background rounded-xl overflow-hidden border border-white/5 shadow-2xl animate-fade-in">
        {/* Left Side: Branding/Visual */}
        <div className="relative hidden md:flex flex-col justify-between p-12 bg-black/80 text-white overflow-hidden">
          <div className="relative z-10">
            <h1 className="font-headline font-black text-4xl text-primary-container uppercase italic leading-none mb-4">
              Join the Hunt
            </h1>
            <p className="text-sm font-light uppercase tracking-widest opacity-80">
              The premier destination for elite diecast collectors.
            </p>
          </div>

          <div className="absolute -bottom-10 -right-20 w-[150%] opacity-20 pointer-events-none transform rotate-[-15deg]">
            <img
              alt="Car Silhouette"
              src="https://lh3.googleusercontent.com/aida-public/AB6AXuBL-AWm0406EG-1UZke8iuF1oZxcY65Vq6dc_9-A1GnFbAoiFAWnkMBVZgKMgaVRrrRUJYiw4nqzaDQd1xGgpwmcWvsEgj79XUUyMY5S2nZYlyPKfUOAWjiQ526D-dlyERFA5g4vM428anIhTgnebUse3SrzDJ-KFXe1uL4dTXtd2m6zn7W9gdZTxRKoEkXLyJSbUtC_04soQqG8Y9gtrtxozmtOzC2Dn_cxQRGR3D-A3F6oSplCvPXJHKZHEGE26GEuAPJ9owfaUc"
            />
          </div>

          <div className="relative z-10 flex items-center gap-2 text-primary-container">
            <span className="material-symbols-outlined">flare</span>
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">
              Diecast Vault established 2026
            </span>
          </div>
        </div>

        {/* Right Side: Form */}
        <div className="p-8 md:p-12 flex flex-col justify-center bg-secondary-container">
          <div className="mb-8">
            <h2 className="text-2xl text-primary-container font-headline font-black uppercase italic mb-2">
              CREATE YOUR ACCOUNT
            </h2>
            <p className="text-sm text-white/90 uppercase tracking-widest">
              Create an account to order reservations
            </p>
          </div>

          <form className="space-y-6" onSubmit={registerAccount}>
            <div className="grid grid-cols-1 md:grid-cols-1 gap-6">
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                  First Name
                </label>
                <input
                  type="text"
                  placeholder="John..."
                  className="w-full bg-input-field border-b border-primary-container  rounded-lg px-4 py-3 text-sm text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                  name="firstName"
                  value={accountForm.firstName}
                  onChange={getInputValue}
                />
              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                  Last Name
                </label>
                <input
                  type="text"
                  placeholder="Doe..."
                  className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                  name="lastName"
                  value={accountForm.lastName}
                  onChange={getInputValue}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                  Gender
                </label>
                <select
                  id="gender"
                  className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                  name="gender"
                  value={accountForm.gender}
                  onChange={getInputValue}
                >
                  <option value="" disabled hidden>
                    Your Gender
                  </option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Prefer Not to Say">Prefer Not to Say</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                  Date of Birth
                </label>
                <input
                  type="date"
                  placeholder="DATE OF BIRTH"
                  className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                  name="dob"
                  value={accountForm.dob}
                  onChange={getInputValue}
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                Email
              </label>
              <input
                type="email"
                placeholder="example@gmail.com"
                className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight"
                name="email"
                value={accountForm.email}
                onChange={getInputValue}
              />
            </div>

            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                Password
              </label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="••••••••"
                  className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight pr-12"
                  name="password"
                  value={accountForm.password}
                  onChange={getInputValue}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-[#A8A8A0] hover:text-white transition-colors"
                >
                  <span className="material-symbols-outlined text-lg">
                    {showPassword ? "visibility" : "visibility_off"}
                  </span>
                </button>
              </div>
            </div>

            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-white/90 mb-2">
                Confirm Password
              </label>
              <div className="relative">
                <input
                  type={showConfirmPassword ? "text" : "password"}
                  placeholder="••••••••"
                  className="w-full bg-input-field border-b border-primary-container rounded-lg px-4 py-3 text-md text-white/90 focus:border-primary-container outline-none transition-colors  tracking-tight pr-12"
                  name="confirmPassword"
                  value={accountForm.confirmPassword}
                  onChange={getInputValue}
                />
                <button
                  type="button"
                  onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-[#A8A8A0] hover:text-white transition-colors"
                >
                  <span className="material-symbols-outlined text-lg">
                    {showConfirmPassword ? "visibility" : "visibility_off"}
                  </span>
                </button>
              </div>
            </div>

            <div className="flex items-center gap-3 py-2 ">
              <input
                type="checkbox"
                id="terms"
                checked={isAgreed}
                onChange={(e) => setIsAgreed(e.target.checked)}
                className="w-4 h-4  accent-primary-container cursor-pointer"
              />
              <label
                htmlFor="terms"
                className="text-xs text-white/90 uppercase tracking-widest cursor-pointer select-none"
              >
                I have read and agree to the{" "}
                <span
                  onClick={(e) => {
                    e.preventDefault();
                    setShowTermsModal(true);
                  }}
                  className="text-primary-container hover:underline italic font-bold"
                >
                  Terms of Service
                </span>
              </label>
            </div>

            <div className="flex items-center gap-3 py-2 ">
              <input
                type="checkbox"
                id="privacy"
                checked={isPrivacyAgreed}
                onChange={(e) => setIsPrivacyAgreed(e.target.checked)}
                className="w-4 h-4  accent-primary-container cursor-pointer"
              />
              <label
                htmlFor="privacy"
                className="text-xs text-white/90 uppercase tracking-widest cursor-pointer select-none"
              >
                I agree to the{" "}
                <span
                  onClick={(e) => {
                    e.preventDefault();
                    setShowPrivacyModal(true);
                  }}
                  className="text-primary-container hover:underline italic font-bold"
                >
                  Data Privacy Policy
                </span>
              </label>
            </div>

            <div className="flex flex-col gap-4">
              <button
                type="button"
                className="w-full flex items-center justify-center gap-3 bg-white hover:scale-105 shadow-lg/30  text-black font-bold py-3 px-4 rounded-lg  transition-all mb-2 border border-gray-300"
                onClick={googleSignUp}
              >
                <img
                  src="https://img.icons8.com/?size=100&id=17949&format=png&color=000000"
                  alt="Google Logo"
                  className="w-5 h-5"
                />
                <span className="uppercase text-xs tracking-widest font-black">
                  Sign up with Google
                </span>
              </button>
              <button
                disabled={!isAgreed || !isPrivacyAgreed}
                className={`w-full py-3 px-4 rounded-lg shadow-lg/30 font-headline font-black uppercase tracking-[0.2em] text-sm transition-all transform active:scale-[0.98] ${
                  isAgreed && isPrivacyAgreed
                    ? "bg-primary-container text-black/90 hover:scale-105  cursor-pointer"
                    : "bg-input-field text-white/90 opacity-50 cursor-not-allowed"
                }`}
              >
                REGISTER
              </button>
            </div>
          </form>

          <div className="mt-8 pt-6  border-t border-primary-container flex flex-col gap-4">
            <p className="text-xs text-white/90 uppercase tracking-widest text-center">
              Already have an account?{" "}
              <Link
                href="/customer/auth/login"
                className="text-primary-container hover:underline italic font-bold"
              >
                SIGN IN
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import CustomerFooter from "../../components/CustomerFooter";
import { createClient } from "../../../lib/supabase/client";
import { useRouter } from "next/navigation";
import Image from "next/image";
import dynamic from "next/dynamic";

const DynamicToast = dynamic(() => import("../../components/Toast"), {
  ssr: false,
});

export default function Feedback() {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState("");
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null); // for checking auth users
  const [toast, setToast] = useState({
    visible: false,
    message: "",
    type: "error",
  });

  const supabase = createClient();
  const router = useRouter();

  const showToast = (message, type = "error") => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ ...toast, visible: false }), 4000);
  };

  // for checking if user is currently logged in when they click RESERVE button
  useEffect(() => {
    const checkUser = async () => {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      console.log("Supabase Auth User:", user);
      setUser(user); // if user is authenticated
    };
    checkUser(); // calls the checkUser function
  }, []);

  const insertFeedback = async (rating, comment) => {
    try {
      if (!user) {
        // is user is not logged in
        showToast("You must login first to comment on this product", "error");
        const captureCurrentPath =
          window.location.pathname + window.location.search; // capture current page url with product id
        setTimeout(() => {
          router.push(
            // pass the captured current path url to login page
            `/customer/auth/login?redirectTo=${encodeURIComponent(captureCurrentPath)}`,
          );
        }, 4000);
        return;
      }

      if (!comment) {
        showToast("Please add comment");
        return;
      }

      const { error } = await supabase.from("Feedback").insert({
        rating: rating,
        comment: comment,
      });

      if (error) throw error;

      showToast("Feedback has been sent!", "success");
      setRating(1);
      setComment("");
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div className="bg-background text-on-surface font-body min-h-screen flex flex-col selection:bg-primary-container selection:text-white">
      <header className="relative py-28 px-12 lg:px-20 border-b border-white/5 overflow-hidden reveal-up">
        <div className="absolute inset-0 bg-black/60 to-transparent z-10"></div>
        <div className="absolute right-0 top-0 w-full h-full pointer-events-none animate-drive-in drop-shadow-lg/30">
          <Image
            className="w-full h-full object-cover"
            src="/porsche-grayscale.jpg"
            alt="Hero BG"
            fill
            priority
            sizes="(max-width: 768px) 100vw, (max-width: 1200px) 100vw, 85vw"
          />
        </div>

        <div className="relative z-20 max-w-[1600px] mx-auto">
          <h1 className="font-headline font-black text-6xl lg:text-[140px] tracking-tighter uppercase leading-[0.8] mb-8 italic">
            <span className="text-primary-container">FEEDBACK</span>
          </h1>

          <div className="flex flex-col sm:flex-row items-start sm:items-center gap-6">
            <span className="text-primary-container text-sm font-black tracking-[0.4em] uppercase">
              We appreciate your responses!
            </span>
          </div>
        </div>
      </header>

      <DynamicToast
        message={toast.message}
        type={toast.type}
        visible={toast.visible}
      />

      {/* Main Feedback View */}
      <main className="flex-1 flex flex-col items-center justify-center max-w-[800px] w-full mx-auto p-6 lg:p-12 gap-10 pt-12 lg:pt-20 mb-20">
        <div className="w-full bg-secondary-container backdrop-blur-xl p-8 lg:p-12 rounded-lg border border-white/5 reveal-up shadow-lg/30 carbon-noise">
          <div className="text-center mb-10">
            <h2 className="font-headline text-2xl lg:text-3xl text-primary-container font-black uppercase tracking-widest italic mb-2">
              Rate Your Experience
            </h2>
            <p className="text-sm font-black uppercase tracking-[0.3em] text-white/90">
              Help us improve our service
            </p>
          </div>

          <div className="flex flex-col items-center gap-8">
            <div className="flex gap-4">
              {[1, 2, 3, 4, 5].map((star) => (
                <button
                  key={star}
                  onClick={() => setRating(star)}
                  className={`material-symbols-outlined text-5xl sm:text-6xl transition-all duration-300 hover:scale-110 active:scale-95 ${
                    rating >= star
                      ? "text-primary-container [font-variation-settings:'FILL'_1] drop-shadow-[0_0_15px_rgba(255,215,0,0.5)]"
                      : "text-white/60 hover:text-primary-container/50 [font-variation-settings:'FILL'_0]"
                  }`}
                >
                  star
                </button>
              ))}
            </div>

            <div className="w-full space-y-4 mt-4">
              <label className="block font-headline font-black text-sm uppercase tracking-[0.3em] text-primary-container ml-1">
                Provide Comment
              </label>
              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Share your thoughts on the order reservation process..."
                className="w-full bg-input-field border-b-2 border-transparent focus:border-primary-container py-6 px-6 rounded-lg text-md text-white/90 font-headline tracking-widest placeholder:text-white/40 focus:outline-none transition-all min-h-[180px] resize-none font-bold"
              />
            </div>

            <button
              className="w-full py-5 mt-6 bg-primary-container drop-shadow-lg/30 rounded-lg font-headline font-black text-sm text-black uppercase tracking-[0.3em] hover:scale-105 transition-all active:scale-[0.98]"
              onClick={() => insertFeedback(rating, comment)}
            >
              Submit Feedback
            </button>
          </div>
        </div>
      </main>

      {/* Footer */}
      <CustomerFooter />

      <style jsx global>{`
        .reveal-up {
          animation: reveal-up 0.8s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
        @keyframes reveal-up {
          0% {
            transform: translateY(30px);
            opacity: 0;
          }
          100% {
            transform: translateY(0);
            opacity: 1;
          }
        }
        .carbon-noise {
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.05'/%3E%3C/svg%3E");
        }
      `}</style>
    </div>
  );
}

const FilterSection = ({ title, children }) => (
  <div className="space-y-6">
    <h3 className="font-headline text-sm font-black uppercase tracking-[0.4em] text-primary-container ">
      {title}
    </h3>
    <div className="flex flex-col gap-4">{children}</div>
  </div>
);

const FilterCheckbox = ({ label, checked, onChange }) => (
  <label className="flex items-center gap-4 cursor-pointer group">
    <div className="relative">
      <input
        type="checkbox"
        checked={checked} // Changed from defaultChecked
        onChange={onChange} // Added the onChange handler
        className="appearance-none size-5 border-2 border-primary-container rounded-md checked:bg-primary-container checked:border-primary-container transition-all"
      />
      {/* 
         IMPORTANT: Use 'checked' (not peer-checked) 
         to show the checkmark icon manually based on state 
      */}
      {checked && (
        <span className="material-symbols-outlined absolute inset-0 text-[14px]  text-black flex items-center justify-center pointer-events-none">
          check
        </span>
      )}
    </div>
    <span
      className={`font-headline text-sm font-black uppercase tracking-widest transition-colors ${checked ? "text-white" : "text-font-color"} group-hover:text-white`}
    >
      {label}
    </span>
  </label>
);

